mapper.update:
UPDATE community_comment
   SET status = #{status}
 WHERE id = #{id}

UPDATE community_comment
   SET content = #{content}
 WHERE id = #{id} AND status = 'PUBLISHED'

UPDATE community_comment
   SET like_count = like_count + 1
 WHERE id = #{id}

UPDATE community_comment
   SET like_count = GREATEST(like_count - 1, 0)
 WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
  FROM community_comment
 WHERE user_id = #{userId}
   AND created_at >= #{since}
   AND status <> 'DELETED'
